const body = $input.first().json.body;

const lead = body.lead || {};
const gaps = body.gaps || [];
const mitre = body.mitreExposure || [];
const frameworks = body.frameworkScores || {};
const qualifiers = body.qualifiers || {};

const riskColors = {
  'Low Risk':      { color: '#22c55e', bg: '#052e16', border: '#22c55e33' },
  'Moderate Risk': { color: '#f59e0b', bg: '#1c1400', border: '#f59e0b33' },
  'High Risk':     { color: '#f97316', bg: '#1a0a00', border: '#f9731633' },
  'Critical Risk': { color: '#ef4444', bg: '#1a0000', border: '#ef444433' },
};
const risk = riskColors[body.riskLevel] || riskColors['High Risk'];

const gapLabels = {
  q1:  'No documented cybersecurity policy approved by leadership',
  q2:  'No up-to-date asset inventory',
  q3:  'MFA not enforced for remote access and privileged accounts',
  q4:  'No formal patch management process with defined SLAs',
  q5:  'No real-time security monitoring or alerting',
  q6:  'Incident response plan missing or never tested',
  q7:  'Backups not tested — recovery not verified',
  q8:  'Least privilege not enforced — over-privileged accounts exist',
  q9:  'Sensitive data not encrypted at rest and in transit',
  q10: 'No cloud security baseline or misconfiguration detection',
  q11: 'No security awareness training for all employees',
  q12: 'No regular vulnerability scanning or tracked remediation',
  q13: 'No secure hardware and media disposal process',
  q14: 'No formal vendor risk assessment program',
  q15: 'Email security controls (SPF/DKIM/DMARC) not fully configured',
  q16: 'Unable to detect/respond to phishing, ransomware, credential theft, or exfiltration',
  q17: 'No AI governance policy or accountability structure',
  q18: 'No AI system impact assessments (AISIA) conducted',
  q19: 'No monitoring of AI systems for drift, bias, or degradation',
  q20: 'AI systems not classified under EU AI Act risk categories',
  q21: 'No human oversight mechanisms for high-risk AI systems',
  q22: 'EU AI Act technical documentation not maintained',
  q23: 'No System Security Plan (SSP) aligned to NIST 800-53 Rev 5',
  q24: 'No FedRAMP continuous monitoring (ConMon) program',
  q25: 'No Plan of Action & Milestones (POA&M) process',
};

const topGaps = gaps.slice(0, 3).map(id => gapLabels[id] || id);

const mitreTactics = {
  'T1078': 'Initial Access', 'T1592': 'Reconnaissance', 'T1110': 'Credential Access',
  'T1190': 'Initial Access', 'T1203': 'Execution', 'T1562': 'Defense Evasion',
  'T1486': 'Impact', 'T1078.003': 'Persistence', 'T1560': 'Collection',
  'T1537': 'Exfiltration', 'T1566': 'Initial Access', 'T1566.001': 'Initial Access',
  'T1005': 'Collection', 'T1195': 'Initial Access', 'T1195.001': 'Initial Access',
  'T1041': 'Exfiltration', 'T1565': 'Impact', 'T1133': 'Initial Access',
};
const uniqueTactics = [...new Set(mitre.map(t => mitreTactics[t]).filter(Boolean))];

const frameworkSummary = Object.entries(frameworks)
  .map(([fw, score]) => `${fw}: ${score}%`)
  .join(' | ');

const qualifierFlags = [];
if (qualifiers.usesAI) qualifierFlags.push('AI/ML');
if (qualifiers.operatesEU) qualifierFlags.push('EU Operations');
if (qualifiers.targetsFederal) qualifierFlags.push('Federal Market');

return [{
  json: {
    name: lead.name || '',
    email: lead.email || '',
    company: lead.company || '',
    size: lead.size || '',
    industry: body.industry?.label || '',
    overallScore: body.overallScore || 0,
    riskLevel: body.riskLevel || '',
    frameworkSummary,
    gap1: topGaps[0] || 'N/A',
    gap2: topGaps[1] || 'N/A',
    gap3: topGaps[2] || 'N/A',
    allGaps: gaps.join(', '),
    mitreCount: mitre.length,
    mitreTacticCount: uniqueTactics.length,
    mitreTechniques: mitre.join(', '),
    qualifierFlags: qualifierFlags.join(', '),
    riskColor: risk.color,
    riskBg: risk.bg,
    riskBorder: risk.border,
  }
}];

